def threeSumClosest(nums: list[int], target: int) -> int:
    nums.sort()
    closest = float('inf')
    for i in range(len(nums) - 2):
        l, r = i + 1, len(nums) - 1
        while l < r:
            s = nums[i] + nums[l] + nums[r]
            if abs(target - s) < abs(target - closest):
                closest = s
            if s < target: l += 1
            elif s > target: r -= 1
            else: return target
    return closest

