function backspaceCompare(s, t) {
    function getValid(strVal, i) {
        let skip = 0;
        while (i >= 0) {
            if (strVal[i] === '#') { skip++; i--; }
            else if (skip > 0) { skip--; i--; }
            else break;
        }
        return i;
    }
    let i = s.length - 1, j = t.length - 1;
    while (i >= 0 || j >= 0) {
        i = getValid(s, i); j = getValid(t, j);
        if (i >= 0 && j >= 0 && s[i] !== t[j]) return false;
        if ((i >= 0) !== (j >= 0)) return false;
        i--; j--;
    }
    return true;
}

