function findUnsortedSubarray(nums) {
    const n = nums.length;
    let maxSeen = -Infinity, minSeen = Infinity;
    let end = -1, start = 0;
    for (let i = 0; i < n; i++) {
        maxSeen = Math.max(maxSeen, nums[i]);
        if (nums[i] < maxSeen) end = i;
