    const n = nums.length;
    function getNext(i, isForward) {
        const direction = nums[i] >= 0;
        if (isForward !== direction) return -1;
        let nextI = (i + nums[i]) % n;
        if (nextI < 0) nextI += n;
        if (nextI === i) return -1;
        return nextI;
    }
    for (let i = 0; i < n; i++) {
        const isForward = nums[i] >= 0;
        let slow = i, fast = i;
        while (true) {
            slow = getNext(slow, isForward);
            fast = getNext(fast, isForward);
            if (fast !== -1) fast = getNext(fast, isForward);
            if (slow === -1 || fast === -1 || slow === fast) break;
