    if (!s || !t) return '';
    const tC = new Map();
    for (const c of t) tC.set(c, (tC.get(c) || 0) + 1);
    let req = tC.size, formed = 0;
    const wC = new Map();
    let l = 0, minL = Infinity, start = 0;
    for (let r = 0; r < s.length; r++) {
        const c = s[r];
        wC.set(c, (wC.get(c) || 0) + 1);
        if (tC.has(c) && wC.get(c) === tC.get(c)) formed++;
        while (l <= r && formed === req) {
            if (r - l + 1 < minL) {
                minL = r - l + 1;
                start = l;
            }
            const cL = s[l];
            wC.set(cL, wC.get(cL) - 1);
            if (tC.has(cL) && wC.get(cL) < tC.get(cL)) formed--;
            l++;
        }
    }
    return minL === Infinity ? '' : s.substring(start, start + minL);
}

