function findSubstring(s, words) {
    if (!s || !words.length) return [];
    const wLen = words[0].length;
    const wCount = words.length;
    const wordMap = new Map();
    for (const w of words) wordMap.set(w, (wordMap.get(w) || 0) + 1);
    const res = [];
    for (let i = 0; i < wLen; i++) {
        let l = i, count = 0;
        const currMap = new Map();
        for (let j = i; j <= s.length - wLen; j += wLen) {
            const word = s.substring(j, j + wLen);
            if (wordMap.has(word)) {
                currMap.set(word, (currMap.get(word) || 0) + 1);
                count++;
                while (currMap.get(word) > wordMap.get(word)) {
                    const leftWord = s.substring(l, l + wLen);
                    currMap.set(leftWord, currMap.get(leftWord) - 1);
                    count--;
                    l += wLen;
                }
                if (count === wCount) res.push(l);
            } else {
                currMap.clear();
                count = 0;
                l = j + wLen;
            }
        }
    }
    return res;
}

